import{_ as h,a as t,e as i,f as c,g as a,h as o,i as g,j as u,k as r,l,b as p,c as m,d as e}from"./chunks/dev_settings_preview.DVlhR-_b.js";import{p as d,bh as s,I as b,U as k}from"./chunks/framework.BpabEsSf.js";const C=JSON.parse('{"title":"Tổng quan giao diện","description":"","frontmatter":{"title":"Tổng quan giao diện","date":"2026-05-01T23:30:00.000Z","permalink":"/guide/overview","categories":["Introduction"],"tags":["Project"]},"headers":[],"relativePath":"vi/01.Guide/01.Introduction/02.Interface Overview.md","filePath":"vi/01.Guide/01.Introduction/02.Interface Overview.md","lastUpdated":null}'),q={name:"vi/01.Guide/01.Introduction/02.Interface Overview.md"};function v(y,n,T,x,M,_){return s(),b("div",null,[...n[0]||(n[0]=[k('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /vi\\01.Guide\\01.Introduction\\02.Interface Overview.md for this page in Markdown format</div><h1 id="tong-quan-giao-dien" tabindex="-1">Tổng quan giao diện <a class="header-anchor" href="#tong-quan-giao-dien" aria-label="Permalink to &quot;Tổng quan giao diện&quot;">​</a></h1><h2 id="tong-quan-chung" tabindex="-1">Tổng quan chung <a class="header-anchor" href="#tong-quan-chung" aria-label="Permalink to &quot;Tổng quan chung&quot;">​</a></h2><p>Monica bao gồm 7 màn hình chính, có thể truy cập thông qua thanh điều hướng phía dưới: Trình quản lý mật khẩu, Trình xác thực 2FA, Ví thẻ, Ghi chú bảo mật, Dòng thời gian/Thùng rác, Trình tạo mật khẩu và Cài đặt.</p><p><img src="'+h+'" alt="Tổng quan chung" loading="lazy"></p><p>Các mục trên thanh điều hướng phía dưới có thể được sắp xếp lại thứ tự hoặc bật/tắt tùy theo sở thích cá nhân của bạn.</p><h2 id="quan-ly-thanh-đieu-huong" tabindex="-1">Quản lý thanh điều hướng <a class="header-anchor" href="#quan-ly-thanh-đieu-huong" aria-label="Permalink to &quot;Quản lý thanh điều hướng&quot;">​</a></h2><p>Bạn có thể chọn chỉ bật những tab thực sự hữu ích với mình, giữ cho thanh điều hướng luôn gọn gàng và không bị rối mắt.</p><p><img src="'+t+'" alt="Quản lý điều hướng" loading="lazy"></p><p>Hãy cùng khám phá màn hình Trình quản lý mật khẩu trước tiên.</p><h2 id="man-hinh-mat-khau" tabindex="-1">Màn hình &quot;Mật khẩu&quot; <a class="header-anchor" href="#man-hinh-mat-khau" aria-label="Permalink to &quot;Màn hình &quot;Mật khẩu&quot;&quot;">​</a></h2><p>Từ trái qua phải: Màn hình chính mật khẩu, thẻ mở rộng của các mục liên kết, chi tiết mật khẩu và giao diện thêm/sửa mật khẩu.</p><p>Giao diện cốt lõi rất đơn giản, giúp bạn dễ dàng tạo và quản lý các tài khoản.</p><p><img src="'+i+'" alt="Màn hình Mật khẩu" loading="lazy"></p><p>Nếu bạn cấu hình &quot;Thông tin tài khoản thường dùng&quot; trong Cài đặt, hệ thống sẽ tự động điền khi tạo mật khẩu mới. Bạn cũng có thể nhấn vào &quot;Đăng nhập bên thứ ba&quot; (như trong hình 2) để tham chiếu hoặc liên kết với các thông tin xác thực khác.</p><p>Thanh công cụ phía trên của màn hình Mật khẩu chứa hai nút: nút bên trái mở menu kéo từ dưới lên để quản lý danh mục; nút thứ hai kiểm soát hành vi xếp chồng các thẻ (tuy nhiên tôi nghĩ cấu hình mặc định đã hoạt động rất tốt rồi!).</p><p><img src="'+c+'" alt="Mẫu tài khoản và Danh mục" loading="lazy"></p><hr><h2 id="man-hinh-trinh-xac-thuc-2fa" tabindex="-1">Màn hình &quot;Trình xác thực 2FA&quot; <a class="header-anchor" href="#man-hinh-trinh-xac-thuc-2fa" aria-label="Permalink to &quot;Màn hình &quot;Trình xác thực 2FA&quot;&quot;">​</a></h2><p>Từ trái qua phải: Giao diện chính của trình xác thực 2FA, giao diện quét mã QR/nhập thủ công và trang chi tiết mã mã hóa 2FA.</p><p>Màn hình 2FA hỗ trợ nhập các chuỗi URI tiêu chuẩn <code>otpauth://</code>. Bạn có thể nhanh chóng quét mã QR hoặc nhập khóa bí mật thủ công để tạo các mã mật khẩu dùng một lần (TOTP).</p><p><img src="'+a+'" alt="Màn hình 2FA" loading="lazy"></p><p>Tại trang chi tiết 2FA, bạn có thể xem các mã xác thực động hiện tại, thời gian hiệu lực còn lại, đồng thời có thể liên kết tài khoản này với một bản ghi mật khẩu cụ thể để liên kết nhanh.</p><hr><h2 id="man-hinh-vi-the" tabindex="-1">Màn hình &quot;Ví thẻ&quot; <a class="header-anchor" href="#man-hinh-vi-the" aria-label="Permalink to &quot;Màn hình &quot;Ví thẻ&quot;&quot;">​</a></h2><p>Từ trái qua phải: Màn hình chính của ví thẻ, giao diện thêm thẻ ngân hàng và trang chi tiết thẻ.</p><p>Trong phần &quot;Thẻ&quot;, bạn có thể lưu trữ an toàn thông tin thẻ tín dụng, thẻ ghi nợ hoặc các loại thẻ định danh khác (như hộ chiếu hoặc bằng lái xe).</p><p><img src="'+o+'" alt="Màn hình Thẻ" loading="lazy"></p><p>Khi thêm thẻ, bạn có thể chỉ định ngân hàng phát hành, số thẻ, thời hạn hiệu lực, mã CVV và tên chủ thẻ. Tất cả các trường này đều được mã hóa trên đĩa cục bộ bằng thuật toán AES-256-GCM.</p><hr><h2 id="man-hinh-ghi-chu-bao-mat" tabindex="-1">Màn hình &quot;Ghi chú bảo mật&quot; <a class="header-anchor" href="#man-hinh-ghi-chu-bao-mat" aria-label="Permalink to &quot;Màn hình &quot;Ghi chú bảo mật&quot;&quot;">​</a></h2><p>Từ trái qua phải: Danh sách ghi chú, giao diện tạo/sửa ghi chú kèm tệp đính kèm và trang xem ghi chú.</p><p>Thành phần &quot;Ghi chú&quot; được thiết kế để lưu trữ các thông tin văn bản riêng tư (như khóa khôi phục, mật khẩu SSH hoặc nhật ký cá nhân).</p><p><img src="'+g+'" alt="Màn hình Ghi chú" loading="lazy"></p><p>Bên cạnh văn bản định dạng thô, bạn có thể đính kèm tệp phương tiện hoặc hình ảnh tài liệu. Các tệp đính kèm được mã hóa và lưu trữ trực tiếp trong sandbox nội bộ cô lập của ứng dụng, ngăn chặn chúng bị lập chỉ mục bởi thư viện ảnh hệ thống của Android.</p><hr><h2 id="man-hinh-dong-thoi-gian-thung-rac" tabindex="-1">Màn hình &quot;Dòng thời gian &amp; Thùng rác&quot; <a class="header-anchor" href="#man-hinh-dong-thoi-gian-thung-rac" aria-label="Permalink to &quot;Màn hình &quot;Dòng thời gian &amp; Thùng rác&quot;&quot;">​</a></h2><p>Từ trái qua phải: Nhật ký kiểm toán (Dòng thời gian) và giao diện quản lý Thùng rác.</p><p>Tab &quot;Dòng thời gian&quot; ghi lại lịch sử thay đổi dữ liệu của bạn (tạo, sửa hoặc xóa bản ghi), cung cấp một quy trình kiểm toán bảo mật cục bộ minh bạch.</p><p><img src="'+u+'" alt="Màn hình Dòng thời gian và Thùng rác" loading="lazy"></p><p>Các mục bị xóa sẽ không bị hủy ngay lập tức — chúng được chuyển vào &quot;Thùng rác&quot;. Bạn có thể khôi phục lại các mật khẩu lỡ tay xóa bất cứ lúc nào hoặc xóa vĩnh viễn để giải phóng dung lượng.</p><hr><h2 id="trinh-tao-mat-khau" tabindex="-1">Trình tạo mật khẩu <a class="header-anchor" href="#trinh-tao-mat-khau" aria-label="Permalink to &quot;Trình tạo mật khẩu&quot;">​</a></h2><p>Từ trái qua phải: Giao diện chính của trình tạo và các tùy chọn thiết lập nâng cao.</p><p>Công cụ này cho phép tạo ra các mật khẩu ngẫu nhiên có độ dài và độ phức tạp cao về mặt mã hóa. Bạn có thể tùy chỉnh độ dài, bật hoặc tắt các chữ số, chữ hoa/chữ thường và các ký tự đặc biệt.</p><p><img src="'+r+'" alt="Trình tạo mật khẩu" loading="lazy"></p><p>Giao diện cũng hỗ trợ tạo các mật khẩu dễ đọc (passphrases) cấu thành từ các từ ngẫu nhiên, giúp con người dễ nhớ hơn nhưng vẫn cực kỳ khó bị bẻ khóa bởi máy tính.</p><hr><h2 id="cac-man-hinh-cai-đat" tabindex="-1">Các màn hình cài đặt <a class="header-anchor" href="#cac-man-hinh-cai-đat" aria-label="Permalink to &quot;Các màn hình cài đặt&quot;">​</a></h2><p>Màn hình Cài đặt được chia thành nhiều mô-đun chức năng: Cá nhân hóa, Quản lý sao lưu, Cài đặt bảo mật và Công cụ phát triển.</p><h3 id="cai-đat-giao-dien-va-ngon-ngu" tabindex="-1">Cài đặt giao diện và ngôn ngữ <a class="header-anchor" href="#cai-đat-giao-dien-va-ngon-ngu" aria-label="Permalink to &quot;Cài đặt giao diện và ngôn ngữ&quot;">​</a></h3><p>Monica hỗ trợ tùy biến sâu giao diện. Bạn có thể chuyển đổi giữa chế độ sáng/tối, cấu hình các gói ngôn ngữ (bao gồm cả tiếng bản địa) và chọn các chủ đề màu sắc cá nhân hóa cho ứng dụng.</p><p><img src="'+l+'" alt="Cài đặt giao diện và chủ đề" loading="lazy"></p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>Ưu tiên màu động hệ thống</strong> Nếu hệ thống đang bật tính năng trích xuất màu từ hình nền (Material You), các bảng màu tùy chỉnh của ứng dụng sẽ tạm thời không được áp dụng. Để thiết lập bảng màu thủ công, vui lòng tắt tính năng trích xuất màu động trong cài đặt của Monica trước.</p></div><h3 id="co-che-monica-plus" tabindex="-1">Cơ chế Monica Plus <a class="header-anchor" href="#co-che-monica-plus" aria-label="Permalink to &quot;Cơ chế Monica Plus&quot;">​</a></h3><p>Monica Plus <strong>không phải</strong> là một phiên bản mở rộng tính năng trả phí hay gói đăng ký bắt buộc. Đây hoàn toàn là một cơ chế quyên góp tự nguyện (donate) dựa trên nguyên tắc trung thực. Nếu bạn thấy dự án hữu ích, bạn có thể kích hoạt trạng thái Plus chỉ với một cú nhấp chuột mà không tốn bất kỳ chi phí thực tế nào. Ứng dụng vẫn hoàn toàn miễn phí!</p><p>Hơn nữa, việc áp dụng cơ chế xác thực thanh toán bắt buộc cho Plus chắc chắn sẽ dẫn đến sự xuất hiện của các phiên bản bẻ khóa (cracks). Việc sử dụng các tệp APK sửa đổi từ bên thứ ba tiềm ẩn rủi ro cài cắm backdoor (cửa sau), đây là một mối đe dọa cực kỳ nghiêm trọng đối với bảo mật trình quản lý mật khẩu của người dùng.</p><h3 id="cai-đat-bao-mat" tabindex="-1">Cài đặt bảo mật <a class="header-anchor" href="#cai-đat-bao-mat" aria-label="Permalink to &quot;Cài đặt bảo mật&quot;">​</a></h3><p>Cài đặt bảo mật là phần quan trọng nhất của ứng dụng:</p><ul><li><strong>Mở khóa sinh trắc học</strong>: Bật &quot;Mở khóa bằng vân tay&quot; cho phép bỏ qua bước nhập Mật khẩu chủ thủ công cho hầu hết các tác vụ hàng ngày. Ban đầu dự án có thiết kế tính năng nhận diện khuôn mặt, tuy nhiên nó thường xuyên nhận diện sai dẫn đến việc vô tình xóa dữ liệu, vì vậy chúng tôi quyết định chỉ giữ lại tính năng quét vân tay.</li><li><strong>Chống ảnh chụp màn hình</strong>: Khi kích hoạt tùy chọn này, hệ thống sẽ chặn việc chụp màn hình hoặc ghi màn hình bên trong giao diện Monica, đảm bảo tính riêng tư tối đa cho dữ liệu trên thiết bị.</li><li><strong>Tự động khóa và khôi phục</strong>: Tại đây bạn có thể đặt thời gian tự động khóa ứng dụng, đổi Mật khẩu chủ và thiết lập các câu hỏi bảo mật.</li></ul><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Nếu bạn không thiết lập câu hỏi bảo mật và đồng thời quên Mật khẩu chủ, bạn sẽ không thể khôi phục quyền truy cập vào kho dữ liệu. Lựa chọn duy nhất lúc này là xóa toàn bộ dữ liệu ứng dụng và thiết lập lại từ đầu.</p></div><ul><li><strong>Trình quản lý quyền</strong>: Trang này mô tả minh bạch tất cả các quyền mà Monica yêu cầu và mục đích của chúng. Monica không bắt buộc người dùng phải cấp bất kỳ quyền nào — ứng dụng vẫn hoạt động bình thường ngay cả khi bạn từ chối tất cả các quyền, chỉ là các tính năng liên quan trực tiếp (như camera để quét mã QR) tạm thời không khả dụng.</li><li><strong>Trình phân tích bảo mật</strong>: Quét cơ sở dữ liệu và đánh giá độ an toàn của các mật khẩu đã lưu, phát hiện các mật khẩu yếu hoặc đã bị rò rỉ. Tính năng này cần kết nối mạng vì nó tương tác với dịch vụ API bên thứ ba uy tín HIBP (Have I Been Pwned), đảm bảo hoàn toàn an toàn và ẩn danh.</li></ul><p><img src="'+p+'" alt="Màn hình cài đặt bảo mật" loading="lazy"></p><hr><h3 id="sao-luu-va-đong-bo-hoa" tabindex="-1">Sao lưu và đồng bộ hóa <a class="header-anchor" href="#sao-luu-va-đong-bo-hoa" aria-label="Permalink to &quot;Sao lưu và đồng bộ hóa&quot;">​</a></h3><p>Mô-đun này chịu trách nhiệm xuất nhập dữ liệu của bạn, đảm bảo tính độc lập không bị ràng buộc vào một thiết bị duy nhất.</p><p><img src="'+m+'" alt="Bảng điều khiển sao lưu" loading="lazy"></p><p>Khi xuất dữ liệu thông qua &quot;Sao lưu toàn bộ&quot;, nhấn vào loại hình xuất mục tiêu lần thứ hai sẽ mở ra cấu hình nâng cao, cho phép bạn chọn hoặc loại bỏ các loại bản ghi cụ thể. Cấu trúc bản sao lưu này hoàn toàn trùng khớp với cấu trúc được sử dụng trong quy trình đồng bộ hóa tự động qua WebDAV.</p><p>Ngoài định dạng nội bộ, ứng dụng hỗ trợ xuất dữ liệu theo cấu trúc tiêu chuẩn của KeePass hoặc sơ đồ của Aegis Authenticator. Điều này giúp bạn dễ dàng di chuyển dữ liệu sang phần mềm khác nếu thấy Monica không còn phù hợp với nhu cầu của mình.</p><p>Tích hợp WebDAV hỗ trợ cả sao lưu các tệp lưu trữ tiêu chuẩn của Monica lẫn đồng bộ hóa tương thích với KeePass. Bản thực thi này mang khả năng hỗ trợ gốc cho các tệp <code>.kdbx</code> trực tiếp vào hệ sinh thái của Monica! Bước tiếp theo trong kế hoạch phát triển (roadmap) của chúng tôi là triển khai cơ chế nhân bản tương thích với Bitwarden, vì tôi muốn công cụ này luôn cực kỳ mạnh mẽ, linh hoạt và đa năng cho mọi người dùng.</p><hr><h3 id="cong-cu-phat-trien" tabindex="-1">Công cụ phát triển <a class="header-anchor" href="#cong-cu-phat-trien" aria-label="Permalink to &quot;Công cụ phát triển&quot;">​</a></h3><p>Cuối cùng là các tiện ích dành cho nhà phát triển và gỡ lỗi mã nguồn.</p><p><img src="'+e+'" alt="Cài đặt nhà phát triển và xem trước" loading="lazy"></p><p>Tab &quot;Tùy chọn nhà phát triển&quot; tích hợp một màn hình hiển thị log thời gian thực để đơn giản hóa quá trình gỡ lỗi. <em>(Hiện tại có một lỗi nhỏ khiến log trong cửa sổ xem đôi khi không cập nhật theo thời gian thực. Vì dù sao tôi cũng gỡ lỗi trực tiếp bên trong Android Studio nên tôi chưa sửa lỗi này, nhưng nó đã nằm trong danh sách việc cần làm của tôi).</em></p><p>Bạn cũng có thể tắt hoàn toàn bước xác thực mật khẩu khi khởi động ứng dụng để tiến hành thử nghiệm nhanh giao diện.</p><p>Trong phần Tính năng thử nghiệm (Preview), các tính năng như thanh kéo điều hướng phía dưới đang được cung cấp. Mặc dù hiện tại chưa thực sự cần thiết, nhưng nó đặt nền móng cho việc triển khai dock hai hàng hỗ trợ vuốt trong tương lai khi các bộ tính năng của Monica mở rộng. Hiện tại hệ thống đang hoạt động rất ổn định, vì vậy hãy giữ mọi thứ thật đơn giản!</p>',77)])])}const A=d(q,[["render",v]]);export{C as __pageData,A as default};
